import { useEffect, useMemo, useState } from "react";
import { BarPanel, PiePanel } from "../components/ChartPanel";
import MetricCard from "../components/MetricCard";
import VoiceInputButton from "../components/VoiceInputButton";
import { createAppointment, createAssessment, createInsuranceRequest, createMedication, createReport, createSymptomLog, getAppointments, getAssessment, getMedications, getProfile, getReports, listInsuranceRequests, sendChatMessage } from "../services/api";

const initialAssessment = { is_previously_treated: false, disease_history: "", document: null };
const nearbyHospitals = [
  { name: "City Care Hospital", address: "12 Wellness Avenue", distance: "2.3 km" },
  { name: "Green Valley Medical Center", address: "88 River Road", distance: "4.1 km" },
  { name: "Sunrise Multispeciality", address: "7 Central Plaza", distance: "5.8 km" },
];

export default function UserDashboardPage() {
  const [profile, setProfile] = useState(null);
  const [assessment, setAssessment] = useState(null);
  const [appointments, setAppointments] = useState([]);
  const [medications, setMedications] = useState([]);
  const [reports, setReports] = useState([]);
  const [insuranceRequests, setInsuranceRequests] = useState([]);
  const [chatMessages, setChatMessages] = useState([]);
  const [symptomForm, setSymptomForm] = useState({ symptom_text: "", source: "text" });
  const [assessmentForm, setAssessmentForm] = useState(initialAssessment);
  const [appointmentForm, setAppointmentForm] = useState({ hospital_name: "", hospital_address: "", appointment_date: "", appointment_time: "", notes: "" });
  const [medicationForm, setMedicationForm] = useState({ medicine_name: "", dosage: "", schedule: "", instructions: "", document: null });
  const [reportForm, setReportForm] = useState({ title: "", report_type: "medical", file: null });
  const [insuranceForm, setInsuranceForm] = useState({ policy_number: "", policy_company: "", treatment_stage: "pre", notes: "" });
  const [chatInput, setChatInput] = useState("");
  const [symptomResult, setSymptomResult] = useState(null);

  const loadData = async () => {
    const [profileData, assessmentData, appointmentData, medicationData, reportData, insuranceData] = await Promise.all([getProfile(), getAssessment(), getAppointments(), getMedications(), getReports(), listInsuranceRequests()]);
    setProfile(profileData);
    setAssessment(assessmentData);
    setAppointments(appointmentData);
    setMedications(medicationData);
    setReports(reportData);
    setInsuranceRequests(insuranceData);
  };

  useEffect(() => { loadData(); }, []);

  const statsForCharts = useMemo(() => ({
    appointmentStatus: appointments.reduce((acc, item) => {
      const found = acc.find((entry) => entry.status === item.status);
      if (found) found.total += 1; else acc.push({ status: item.status, total: 1 });
      return acc;
    }, []),
    reportTypes: reports.reduce((acc, item) => {
      const found = acc.find((entry) => entry.status === item.report_type);
      if (found) found.total += 1; else acc.push({ status: item.report_type, total: 1 });
      return acc;
    }, []),
  }), [appointments, reports]);

  const speakResponse = (text) => {
    if (!window.speechSynthesis) return;
    const utterance = new SpeechSynthesisUtterance(text);
    utterance.lang = "en-US";
    window.speechSynthesis.speak(utterance);
  };

  const handleAssessmentSubmit = async (event) => {
    event.preventDefault();
    const data = await createAssessment(assessmentForm);
    setAssessment(data);
    setProfile((prev) => ({ ...prev, first_login_completed: true }));
    setAssessmentForm(initialAssessment);
  };

  const handleSymptomSubmit = async (event) => {
    event.preventDefault();
    const data = await createSymptomLog(symptomForm);
    setSymptomResult(data);
    speakResponse(`Possible issue ${data.predicted_disease}`);
    setSymptomForm({ symptom_text: "", source: "text" });
  };

  const handleAppointmentSubmit = async (event) => {
    event.preventDefault();
    await createAppointment(appointmentForm);
    setAppointmentForm({ hospital_name: "", hospital_address: "", appointment_date: "", appointment_time: "", notes: "" });
    loadData();
  };

  const handleMedicationSubmit = async (event) => {
    event.preventDefault();
    await createMedication(medicationForm);
    setMedicationForm({ medicine_name: "", dosage: "", schedule: "", instructions: "", document: null });
    loadData();
  };

  const handleReportSubmit = async (event) => {
    event.preventDefault();
    await createReport(reportForm);
    setReportForm({ title: "", report_type: "medical", file: null });
    loadData();
  };

  const handleInsuranceSubmit = async (event) => {
    event.preventDefault();
    await createInsuranceRequest(insuranceForm);
    setInsuranceForm({ policy_number: "", policy_company: "", treatment_stage: "pre", notes: "" });
    loadData();
  };

  const handleChatSubmit = async (event) => {
    event.preventDefault();
    const response = await sendChatMessage(chatInput);
    setChatMessages((prev) => [...prev, { user: chatInput, bot: response.message, action: response.action }]);
    speakResponse(response.message);
    setChatInput("");
  };

  return (
    <>
      <div className="card-grid">
        <MetricCard label="Profile status" value={profile?.first_login_completed ? "Assessment done" : "Assessment pending"} />
        <MetricCard label="Appointments" value={appointments.length} />
        <MetricCard label="Medications" value={medications.length} />
        <MetricCard label="Reports scanned" value={reports.length} />
      </div>
      <div className="split-layout">
        <div style={{ display: "grid", gap: 18 }}>
          {!profile?.first_login_completed ? (
            <div className="panel">
              <h3 className="section-title">First Login Assessment</h3>
              <form onSubmit={handleAssessmentSubmit}>
                <div className="field"><label>Are you previously treated or is this your first time?</label><select value={assessmentForm.is_previously_treated ? "yes" : "no"} onChange={(e) => setAssessmentForm({ ...assessmentForm, is_previously_treated: e.target.value === "yes" })}><option value="no">First time</option><option value="yes">Previously treated</option></select></div>
                <div className="field"><label>Disease history</label><textarea value={assessmentForm.disease_history} onChange={(e) => setAssessmentForm({ ...assessmentForm, disease_history: e.target.value })} /></div>
                <div className="field"><label>Upload medical document (PDF)</label><input type="file" accept="application/pdf" onChange={(e) => setAssessmentForm({ ...assessmentForm, document: e.target.files?.[0] || null })} /></div>
                <button className="btn btn-primary" type="submit">Generate Assessment</button>
              </form>
              {assessment?.generated_questions?.length ? <div style={{ marginTop: 16 }}><strong>Suggested questions</strong><ul>{assessment.generated_questions.map((question, index) => <li key={`${question.question}-${index}`}>{question.question}</li>)}</ul></div> : null}
            </div>
          ) : null}
          <div className="panel">
            <h3 className="section-title">Symptom Checker</h3>
            <form onSubmit={handleSymptomSubmit}>
              <div className="field"><label>Describe symptoms</label><textarea value={symptomForm.symptom_text} onChange={(e) => setSymptomForm({ ...symptomForm, symptom_text: e.target.value })} /></div>
              <div className="button-row"><button className="btn btn-primary" type="submit">Analyze Symptoms</button><VoiceInputButton onTranscript={(text) => setSymptomForm({ symptom_text: text, source: "voice" })} /></div>
            </form>
            {symptomResult ? <div style={{ marginTop: 16 }}><p><strong>Predicted disease:</strong> {symptomResult.predicted_disease}</p><p><strong>Confidence:</strong> {(symptomResult.confidence_score * 100).toFixed(0)}%</p><ul>{symptomResult.suggestions.map((suggestion) => <li key={suggestion}>{suggestion}</li>)}</ul></div> : null}
          </div>
          <div className="panel">
            <h3 className="section-title">Appointment Scheduling</h3>
            <div className="card-grid" style={{ marginBottom: 16 }}>{nearbyHospitals.map((hospital) => <div className="metric-card" key={hospital.name}><span className="muted">Nearby option</span><strong style={{ fontSize: "1.1rem" }}>{hospital.name}</strong><div>{hospital.address}</div><div className="muted">{hospital.distance}</div><button type="button" className="btn btn-secondary" style={{ marginTop: 10 }} onClick={() => setAppointmentForm({ ...appointmentForm, hospital_name: hospital.name, hospital_address: hospital.address })}>Use This Hospital</button></div>)}</div>
            <form onSubmit={handleAppointmentSubmit}>
              <div className="form-grid">
                <div className="field"><label>Hospital</label><input value={appointmentForm.hospital_name} onChange={(e) => setAppointmentForm({ ...appointmentForm, hospital_name: e.target.value })} /></div>
                <div className="field"><label>Address</label><input value={appointmentForm.hospital_address} onChange={(e) => setAppointmentForm({ ...appointmentForm, hospital_address: e.target.value })} /></div>
                <div className="field"><label>Date</label><input type="date" value={appointmentForm.appointment_date} onChange={(e) => setAppointmentForm({ ...appointmentForm, appointment_date: e.target.value })} /></div>
                <div className="field"><label>Time</label><input type="time" value={appointmentForm.appointment_time} onChange={(e) => setAppointmentForm({ ...appointmentForm, appointment_time: e.target.value })} /></div>
              </div>
              <div className="field"><label>Notes</label><textarea value={appointmentForm.notes} onChange={(e) => setAppointmentForm({ ...appointmentForm, notes: e.target.value })} /></div>
              <button className="btn btn-primary" type="submit">Request Appointment</button>
            </form>
          </div>
        </div>
        <div style={{ display: "grid", gap: 18 }}>
          <div className="panel">
            <h3 className="section-title">Medication Module</h3>
            <form onSubmit={handleMedicationSubmit}>
              <div className="field"><label>Medicine name</label><input value={medicationForm.medicine_name} onChange={(e) => setMedicationForm({ ...medicationForm, medicine_name: e.target.value })} /></div>
              <div className="form-grid"><div className="field"><label>Dosage</label><input value={medicationForm.dosage} onChange={(e) => setMedicationForm({ ...medicationForm, dosage: e.target.value })} /></div><div className="field"><label>Schedule</label><input value={medicationForm.schedule} onChange={(e) => setMedicationForm({ ...medicationForm, schedule: e.target.value })} /></div></div>
              <div className="field"><label>Instructions</label><textarea value={medicationForm.instructions} onChange={(e) => setMedicationForm({ ...medicationForm, instructions: e.target.value })} /></div>
              <div className="field"><label>Upload prescription PDF</label><input type="file" accept="application/pdf" onChange={(e) => setMedicationForm({ ...medicationForm, document: e.target.files?.[0] || null })} /></div>
              <button className="btn btn-primary" type="submit">Save Medication</button>
            </form>
          </div>
          <div className="panel">
            <h3 className="section-title">Report Scanner</h3>
            <form onSubmit={handleReportSubmit}>
              <div className="field"><label>Report title</label><input value={reportForm.title} onChange={(e) => setReportForm({ ...reportForm, title: e.target.value })} /></div>
              <div className="field"><label>Type</label><select value={reportForm.report_type} onChange={(e) => setReportForm({ ...reportForm, report_type: e.target.value })}><option value="medical">Medical Report</option><option value="medication">Medication</option><option value="assessment">Assessment</option></select></div>
              <div className="field"><label>Upload report PDF</label><input type="file" accept="application/pdf" onChange={(e) => setReportForm({ ...reportForm, file: e.target.files?.[0] || null })} /></div>
              <button className="btn btn-primary" type="submit">Store Report</button>
            </form>
          </div>
          <div className="panel">
            <h3 className="section-title">Insurance Assistance</h3>
            <form onSubmit={handleInsuranceSubmit}>
              <div className="field"><label>Policy Number</label><input value={insuranceForm.policy_number} onChange={(e) => setInsuranceForm({ ...insuranceForm, policy_number: e.target.value })} /></div>
              <div className="field"><label>Policy Company</label><input value={insuranceForm.policy_company} onChange={(e) => setInsuranceForm({ ...insuranceForm, policy_company: e.target.value })} /></div>
              <div className="field"><label>Pre/Post Treatment</label><select value={insuranceForm.treatment_stage} onChange={(e) => setInsuranceForm({ ...insuranceForm, treatment_stage: e.target.value })}><option value="pre">Pre-Treatment</option><option value="post">Post-Treatment</option></select></div>
              <div className="field"><label>Notes</label><textarea value={insuranceForm.notes} onChange={(e) => setInsuranceForm({ ...insuranceForm, notes: e.target.value })} /></div>
              <button className="btn btn-primary" type="submit">Submit Insurance Request</button>
            </form>
          </div>
        </div>
      </div>
      <div className="split-layout">
        <div className="panel">
          <h3 className="section-title">Chatbot Assistant</h3>
          <div className="chat-box" style={{ marginBottom: 16 }}>{chatMessages.map((item, index) => <div className="chat-message" key={`${item.user}-${index}`}><strong>You</strong><div>{item.user}</div><strong style={{ marginTop: 10 }}>Bot</strong><div>{item.bot}</div>{item.action ? <span className="pill" style={{ marginTop: 8 }}>{item.action}</span> : null}</div>)}</div>
          <form onSubmit={handleChatSubmit}><div className="field"><label>Ask anything</label><textarea value={chatInput} onChange={(e) => setChatInput(e.target.value)} placeholder="Book appointment tomorrow or give diet plan" /></div><button className="btn btn-primary" type="submit">Send</button></form>
        </div>
        <div style={{ display: "grid", gap: 18 }}>
          <div className="panel">
            <h3 className="section-title">Health History Snapshot</h3>
            <p className="muted">Assessment summary</p><p>{assessment?.summary || "Assessment summary will appear here after the first-login flow."}</p>
            <p className="muted">Medication schedules</p><ul>{medications.slice(0, 4).map((medication) => <li key={medication.id}>{medication.medicine_name} � {medication.schedule}</li>)}</ul>
            <p className="muted">Insurance requests</p><ul>{insuranceRequests.slice(0, 4).map((item) => <li key={item.id}>{item.policy_company} � {item.status}</li>)}</ul>
          </div>
          <BarPanel title="Appointment Status Overview" data={statsForCharts.appointmentStatus} />
          <PiePanel title="Report Type Distribution" data={statsForCharts.reportTypes} />
        </div>
      </div>
      <div className="panel" style={{ marginTop: 18 }}>
        <h3 className="section-title">Recent Appointments</h3>
        <div className="table-wrap"><table><thead><tr><th>Hospital</th><th>Date</th><th>Time</th><th>Status</th></tr></thead><tbody>{appointments.map((appointment) => <tr key={appointment.id}><td>{appointment.hospital_name}</td><td>{appointment.appointment_date}</td><td>{appointment.appointment_time}</td><td><span className="pill">{appointment.status}</span></td></tr>)}</tbody></table></div>
      </div>
    </>
  );
}
